							? html`<div class="text-xs text-[var(--muted)] mt-1">
							${
								keyHelp.url
									? html`${keyHelp.text} <a href=${keyHelp.url} target="_blank" rel="noopener noreferrer" class="text-[var(--accent)] underline">${keyHelp.label || keyHelp.url}</a>`
